113: // ShouldSetHostname returns true if the Hostname attribute should be set on an
114: // Endpoints Address or EndpointSlice Endpoint.
115: func ShouldSetHostname(pod *v1.Pod, svc *v1.Service) bool {
116: 	return len(pod.Spec.Hostname) > 0 && pod.Spec.Subdomain == svc.Name && svc.Namespace == pod.Namespace
117: }
