222: func determineNeededServiceUpdates(oldServices, services sets.String, podChanged bool) sets.String {
223: 	if podChanged {
224: 		// if the labels and pod changed, all services need to be updated
225: 		services = services.Union(oldServices)
226: 	} else {
227: 		// if only the labels changed, services not common to both the new
228: 		// and old service set (the disjuntive union) need to be updated
229: 		services = services.Difference(oldServices).Union(oldServices.Difference(services))
230: 	}
231: 	return services
232: }
