277: // boolPtrChanged returns true if a set of bool pointers have different values.
278: func boolPtrChanged(ptr1, ptr2 *bool) bool {
279: 	if (ptr1 == nil) != (ptr2 == nil) {
280: 		return true
281: 	}
282: 	if ptr1 != nil && ptr2 != nil && *ptr1 != *ptr2 {
283: 		return true
284: 	}
285: 	return false
286: }
