320: // IsPodTerminal returns true if a pod is terminal, all containers are stopped and cannot ever regress.
321: // copied from k8s.io/kubernetes/pkg/api/v1/pod
322: func isPodTerminal(pod *v1.Pod) bool {
323: 	return isPodPhaseTerminal(pod.Status.Phase)
324: }
