326: // IsPodPhaseTerminal returns true if the pod's phase is terminal.
327: // copied from k8s.io/kubernetes/pkg/api/v1/pod
328: func isPodPhaseTerminal(phase v1.PodPhase) bool {
329: 	return phase == v1.PodFailed || phase == v1.PodSucceeded
