332: // IsPodReadyConditionTrue returns true if a pod is ready; false otherwise.
333: // copied from k8s.io/kubernetes/pkg/api/v1/pod
334: func isPodReadyConditionTrue(status v1.PodStatus) bool {
335: 	condition := getPodReadyCondition(&status)
336: 	return condition != nil && condition.Status == v1.ConditionTrue
337: }
