339: // getPodReadyCondition extracts the pod ready condition from the given status and returns that.
340: // Returns nil if the condition is not present.
341: // copied from k8s.io/kubernetes/pkg/api/v1/pod
342: func getPodReadyCondition(status *v1.PodStatus) *v1.PodCondition {
343: 	if status == nil || status.Conditions == nil {
344: 		return nil
345: 	}
346: 
347: 	for i := range status.Conditions {
348: 		if status.Conditions[i].Type == v1.PodReady {
349: 			return &status.Conditions[i]
350: 		}
351: 	}
352: 	return nil
353: }
